const q = $json.query || {};
const lead = {
  type: q.type || 'enquiry',
  name: q.name || '',
  email: q.email || '',
  phone: q.phone || '',
  goal: q.goal || '',
  message: q.message || '',
  submittedAt: new Date().toISOString(),
};

lead.emailSubject = `New investment enquiry from ${lead.name || 'website visitor'}`;
lead.emailMessage = [
  'New investment advisory enquiry received from the website.',
  '',
  `Name: ${lead.name}`,
  `Email: ${lead.email}`,
  `Phone: ${lead.phone}`,
  `Investment Goal: ${lead.goal}`,
  '',
  'Message:',
  lead.message,
].join('\n');

lead.success = true;
lead.responseMessage = 'Thank you. Your enquiry has been received.';
return [{ json: lead }];

return [{
  json: {
    success: true,
    message: 'Thank you. Your enquiry has been received.'
  }
}];

const body = $json.body || $json;
return [{
  json: {
    type: body.type || 'chat',
    message: body.message || '',
    name: body.name || '',
    phone: body.phone || body.tel || '',
    email: body.email || '',
    source: body.source || 'investment-advisor-website',
    sessionId: body.sessionId || body.email || body.phone || body.source || 'investment-advisor-website'
  }
}];
